 1	import * as React from 'react';
 2	import { FC, ReactNode } from 'react';
 3	import classNames from 'classnames';
 4	
 5	import { Popover, PopoverPosition } from '@patternfly/react-core';
 6	import { HelpIcon } from '@patternfly/react-icons';
 7	
 8	import './HelpTextIcon.scss';
 9	
10	type HelpTextIconProps = {
11	  bodyContent: ReactNode;
12	  className?: string;
13	  helpIconClassName?: string;
14	  position?: PopoverPosition;
15	};
16	
17	const HelpTextIcon: FC<HelpTextIconProps> = ({
18	  bodyContent,
19	  className = 'help-text-icon__popover',
20	  helpIconClassName = '',
21	  position = PopoverPosition.top,
22	}) => (
23	  <Popover aria-label={'Help'} bodyContent={bodyContent} className={className} position={position}>
24	    <HelpIcon className={classNames('help-icon__cursor', helpIconClassName)} />
25	  </Popover>
26	);
27	
28	export default HelpTextIcon;

